class Solution:
    def removeSubfolders(self, folder):
        s = set(folder)
        res = []
        for f in folder:
            parts = f.split('/')
            dominated = False
            for i in range(1, len(parts)):
                ancestor = '/'.join(parts[:i])
                if ancestor and ancestor in s:
                    dominated = True
                    break
            if not dominated:
                res.append(f)
        return res

